import React from 'react'
import { RxCross1 } from "react-icons/rx";
export const TOAST_TYPE = {
    SUCCESS: 'success',
    ERROR: 'error',
    WARNING: 'warning'
}

function Toast({ content, timer, type, onClose }) {
    function getBackground(type) {
        let color = 'grey'
        switch (type) {
            case TOAST_TYPE.SUCCESS: color = 'green'
                break
            case TOAST_TYPE.ERROR: color = 'red'
                break
            case TOAST_TYPE.WARNING: color = 'orange'
                break
        }
        return color
    }
    function handleClose() {
        onClose()
    }
    return (
        <div style={{ backgroundColor: getBackground(type) }} className='toast'>
            <div>{content}</div>
            <button onClick={handleClose}><RxCross1 /></button>
        </div>
    )
}

export default Toast
